      IntArray::full(a, n, la) *
      IntArray::full(b, m, lb) *
      IntArray::full(out, n + m, lo)
    Ensure
      Zlength(merge_sorted_arrays_spec(la, lb)) == n + m &&
      IntArray::full(a, n, la) *
      IntArray::full(b, m, lb) *
      IntArray::full(out, n + m, merge_sorted_arrays_spec(la, lb))
*/
{
